// src/components/FuelPriceWidget.jsx
// ─────────────────────────────────────────────────────────────────────
//  LIVE FUEL PRICES — Powered by Zyla Labs Fuel India API
//
//  FREE SETUP (2 minutes):
//  1. Go to → https://zylalabs.com/api-marketplace/market+data+&+trading/fuel+india+api/5879
//  2. Click "Start Free Trial" → sign up with email
//  3. Copy your Bearer token from dashboard
//  4. Paste it below in ZYLA_API_KEY
// ─────────────────────────────────────────────────────────────────────

import React, { useState, useEffect } from 'react';
import './FuelPriceWidget.css';

// ── PASTE YOUR KEY HERE ──────────────────────────────────────────────
const ZYLA_API_KEY = 'YOUR_ZYLA_BEARER_TOKEN_HERE';
// ────────────────────────────────────────────────────────────────────

const API_BASE = 'https://zylalabs.com/api/5879/fuel+india+api/7728/fuel+prices+by+state+and+city';

// City config: state & city as Zyla expects (lowercase, hyphenated)
const CITIES = [
  { label: 'Delhi',     state: 'delhi',          city: 'delhi'     },
  { label: 'Faridabad', state: 'haryana',         city: 'faridabad' },
  { label: 'Gurugram',  state: 'haryana',         city: 'gurugram'  },
  { label: 'Noida',     state: 'uttar-pradesh',   city: 'noida'     },
  { label: 'Lucknow',   state: 'uttar-pradesh',   city: 'lucknow'   },
  { label: 'Jaipur',    state: 'rajasthan',       city: 'jaipur'    },
];

const FUELS = [
  { key: 'Petrol', icon: '⛽', color: '#f97316', bg: '#fff7ed' },
  { key: 'Diesel', icon: '🛢️', color: '#16a34a', bg: '#f0fdf4' },
];

// Module-level cache: { [cityLabel]: { data, fetchedAt } }
const CACHE = {};
const CACHE_TTL_MS = 60 * 60 * 1000; // 1 hour

async function fetchCityPrices(cityDef) {
  const now = Date.now();
  const cached = CACHE[cityDef.label];
  if (cached && now - cached.fetchedAt < CACHE_TTL_MS) {
    return cached.data;
  }

  const url = `${API_BASE}?state=${cityDef.state}&city=${cityDef.city}`;
  const res = await fetch(url, {
    method: 'GET',
    headers: {
      Authorization: `Bearer ${ZYLA_API_KEY}`,
      'Content-Type': 'application/json',
    },
  });

  if (!res.ok) {
    const errText = await res.text().catch(() => '');
    throw new Error(`API error ${res.status}: ${errText}`);
  }

  const json = await res.json();

  // Zyla response shape:
  // { fuel: { petrol: { retailPrice, retailPriceChange }, diesel: { ... } } }
  const fuel = json?.fuel ?? json?.data?.fuel ?? null;
  if (!fuel) throw new Error('Unexpected API response shape');

  const result = {
    petrol:       parseFloat(fuel.petrol?.retailPrice       ?? 0),
    diesel:       parseFloat(fuel.diesel?.retailPrice       ?? 0),
    petrolChange: parseFloat(fuel.petrol?.retailPriceChange ?? 0),
    dieselChange: parseFloat(fuel.diesel?.retailPriceChange ?? 0),
    date:         json?.applicableOn ?? json?.date ?? new Date().toISOString().slice(0, 10),
  };

  CACHE[cityDef.label] = { data: result, fetchedAt: now };
  return result;
}

function formatDate(isoStr) {
  return new Date(isoStr).toLocaleDateString('en-IN', {
    day: 'numeric', month: 'short', year: 'numeric',
  });
}

function todayStr() {
  return new Date().toLocaleDateString('en-IN', {
    day: 'numeric', month: 'short', year: 'numeric',
  });
}

// ─────────────────────────────────────────────────────────────────────
export default function FuelPriceWidget() {
  const [cityDef, setCityDef]     = useState(CITIES[0]);
  const [data, setData]           = useState(null);
  const [loading, setLoading]     = useState(true);
  const [error, setError]         = useState(null);

  const noKeySet = ZYLA_API_KEY === 'YOUR_ZYLA_BEARER_TOKEN_HERE';

  useEffect(() => {
    if (noKeySet) { setLoading(false); return; }

    let cancelled = false;
    setLoading(true);
    setError(null);
    setData(null);

    fetchCityPrices(cityDef)
      .then(d => { if (!cancelled) { setData(d); setLoading(false); } })
      .catch(e => { if (!cancelled) { setError(e.message); setLoading(false); } });

    return () => { cancelled = true; };
  }, [cityDef, noKeySet]);

  // Trend helper
  const trend = (change) => {
    if (change > 0.009)  return { color: '#ef4444', arrow: '↑', label: `+₹${change.toFixed(2)}` };
    if (change < -0.009) return { color: '#16a34a', arrow: '↓', label: `-₹${Math.abs(change).toFixed(2)}` };
    return { color: '#6b7280', arrow: '→', label: 'No change' };
  };

  return (
    <div className="fpw-root">

      {/* ── Header ── */}
      <div className="fpw-header">
        <div className="fpw-header-left">
          <span className="fpw-live-dot" />
          <span className="fpw-title">Live Fuel Prices</span>
          {data && (
            <span className="fpw-updated">🟢 Live · {formatDate(data.date)}</span>
          )}
        </div>
        <select
          className="fpw-city-select"
          value={cityDef.label}
          onChange={e => setCityDef(CITIES.find(c => c.label === e.target.value))}
          disabled={noKeySet}
        >
          {CITIES.map(c => <option key={c.label}>{c.label}</option>)}
        </select>
      </div>

      {/* ── Body ── */}
      <div className="fpw-body">

        {/* API key not set */}
        {noKeySet && (
          <div className="fpw-loading" style={{ flexDirection: 'column', gap: 8, alignItems: 'flex-start', padding: '16px 20px' }}>
            <strong style={{ color: '#ef4444' }}>⚠️ API Key Not Set</strong>
            <p style={{ fontSize: 13, color: '#6b7280', lineHeight: 1.5 }}>
              1. Go to{' '}
              <a href="https://zylalabs.com/api-marketplace/market+data+&+trading/fuel+india+api/5879"
                 target="_blank" rel="noreferrer"
                 style={{ color: '#f97316' }}>
                zylalabs.com → Fuel India API
              </a>
              <br />
              2. Click <strong>"Start Free Trial"</strong> → sign up free
              <br />
              3. Paste your Bearer token in <code>ZYLA_API_KEY</code> in this file
            </p>
          </div>
        )}

        {/* Loading */}
        {!noKeySet && loading && (
          <div className="fpw-loading">
            <span className="fpw-spinner" />
            <span>Fetching live prices…</span>
          </div>
        )}

        {/* Error */}
        {!noKeySet && !loading && error && (
          <div className="fpw-loading" style={{ color: '#ef4444', fontSize: 13, padding: '14px 20px' }}>
            ⚠️ {error.includes('401') || error.includes('403')
              ? 'Invalid API key. Check your Zyla Bearer token.'
              : `Could not load prices: ${error}`}
          </div>
        )}

        {/* Price rows */}
        {!loading && !error && data && FUELS.map(f => {
          const price  = f.key === 'Petrol' ? data.petrol  : data.diesel;
          const change = f.key === 'Petrol' ? data.petrolChange : data.dieselChange;
          const t      = trend(change);
          // Yesterday approx
          const yesterday = (price - change).toFixed(2);

          return (
            <div key={f.key} className="fpw-row" style={{ '--fc': f.color, '--fb': f.bg }}>

              <div className="fpw-row-left">
                <span className="fpw-row-icon">{f.icon}</span>
                <span className="fpw-row-name">{f.key}</span>
              </div>

              <div className="fpw-today">
                <span className="fpw-today-label">Today</span>
                <span className="fpw-today-price">₹{price.toFixed(2)}</span>
                <span className="fpw-today-unit">/ litre</span>
              </div>

              <div className="fpw-divider" />

              <div className="fpw-past">
                <span className="fpw-past-label">Yesterday</span>
                <span className="fpw-past-price">₹{yesterday}</span>
              </div>

              <div className="fpw-badge" style={{ background: t.color + '18', color: t.color }}>
                <span className="fpw-badge-arrow">{t.arrow}</span>
                <span className="fpw-badge-val">{t.label}</span>
              </div>

            </div>
          );
        })}
      </div>

      {/* ── Footer ── */}
      <div className="fpw-footer">
        {data
          ? <span>📍 <strong>{cityDef.label}</strong> · Incl. VAT &amp; local levies · {todayStr()}</span>
          : !noKeySet && !loading && <span style={{ color: '#6b7280' }}>Price data unavailable</span>
        }
      </div>

    </div>
  );
}
